const ALLOWED_METHODS = "GET, POST, PUT, DELETE, OPTIONS";
const ALLOWED_HEADERS = "Content-Type, Authorization, X-Request-ID";
const MAX_AGE = "3600";

function handleCORS(req, res) {
  const origin = req.headers.origin;
  const path = new URL(req.url, `http://${req.headers.host || "localhost"}`).pathname;

  // Health endpoint must NOT include CORS headers (API_GATEWAY_SPEC.md)
  if (path === "/health") {
    return;
  }

  // Only set CORS headers for allowed origins
  if (origin && ALLOWED_ORIGINS.includes(origin)) {
    // Echo the specific requesting origin (required when credentials=true)
    res.setHeader("Access-Control-Allow-Origin", origin);

    // Enable credentials (session cookies)
    res.setHeader("Access-Control-Allow-Credentials", "true");

    // Set allowed methods and headers
    res.setHeader("Access-Control-Allow-Methods", ALLOWED_METHODS);
    res.setHeader("Access-Control-Allow-Headers", ALLOWED_HEADERS);

    // Preflight cache duration
    res.setHeader("Access-Control-Max-Age", MAX_AGE);

    // Prevent cache poisoning (critical for CDN)
    res.setHeader("Vary", "Origin");
  }
}

function parseBody(req) {
